/// A controller class that manages [Team] search for super_admin and super_reader.
///
/// This controller refreshes itself when
/// - [repositoryProvider] updated.
/// - [loginStateControllerProvider] updated.
/// - [teamSearchFilterParametersNotifierProvider] updated.
///
/// Note: This controller just handles abstract repository.
/// This means that the controller does not care
/// the implementation of its repository is either remote DB or local cache.
/// Therefore do not use anything related to a specific implementation of repository
/// (e.g., the login state of the remote DB).
@Riverpod(keepAlive: true)
class SuperAdminTeamSearchController extends _$SuperAdminTeamSearchController
    with PagePagingNotifierMixin<Team> {
  static const int pageSize = 100;

  @override
  Future<PagingData<Team>> build() {
    ref.watch(loginStateControllerProvider);
    ref.watch(repositoryProvider);
    final filterParams = ref.watch(teamSearchFilterParametersNotifierProvider);
    return fetch(
      page: PagePagingNotifierMixin.initialPage,
      pageSize: pageSize,
      filterParams: filterParams,
    );
  }

  @override
  Future<PagingData<Team>> fetch({
    required int page,
    required int pageSize,
    TeamSearchFilterParameters? filterParams,
  }) async {
    final TeamSearchFilterParameters params =
        filterParams ?? ref.read(teamSearchFilterParametersNotifierProvider);

    final res = await ref.read(repositoryProvider).searchTeams(
          keyword: params.keyword,
          page: page,
          pageSize: pageSize,
          orderBy: params.orderBy,
          isOrderDesc: params.isOrderDesc,
          // Super Admin フィルタ
          isPlanPaid: params.isPlanPaid,
          isTeamPlanActive: params.isTeamPlanActive,
          teamTypes: params.teamTypes,
          ownerEmail: params.ownerEmail,
          // 日付フィルタは将来実装
          teamPlanStartDateFrom: params.teamPlanStartDateFrom,
          teamPlanStartDateTo: params.teamPlanStartDateTo,
          teamPlanEndDateFrom: params.teamPlanEndDateFrom,
          teamPlanEndDateTo: params.teamPlanEndDateTo,
          extendToNextTeamPlan: params.extendToNextTeamPlan,
          isDeletionScheduled: params.isDeletionScheduled,
        );

    checkResultForMaintenance(ref, res);
    if (!res.hasRight) {
      throw res.left;
    }

    return PagingData<Team>(
      items: res.right.teams,
      page: page,
      pageSize: pageSize,
      total: res.right.total,
      hasMore: res.right.teams.length + page * pageSize < res.right.total,
    );
  }
}

/// Filtering parameters for SuperAdminTeamSearchController.
///
/// This class is the state of TeamSearchFilterParametersNotifier.
/// The state of StateNotifier should be immutable.
@immutable
class TeamSearchFilterParameters {
  // 基本フィルタ
  final String? keyword;
  final TeamSearchRequestOrderBy orderBy;
  final bool? isOrderDesc;

  // Super Admin フィルタ
  final bool? isPlanPaid;
  final bool? isTeamPlanActive;
  final List<TeamType>? teamTypes;
  final String? ownerEmail;
  final DateTime? teamPlanStartDateFrom;
  final DateTime? teamPlanStartDateTo;
  final DateTime? teamPlanEndDateFrom;
  final DateTime? teamPlanEndDateTo;
  final bool? extendToNextTeamPlan;
  final bool? isDeletionScheduled;

  const TeamSearchFilterParameters({
    this.keyword,
    this.orderBy = TeamSearchRequestOrderBy.name,
    this.isOrderDesc,
    this.isPlanPaid,
    this.isTeamPlanActive,
    this.teamTypes,
    this.ownerEmail,
    this.teamPlanStartDateFrom,
    this.teamPlanStartDateTo,
    this.teamPlanEndDateFrom,
    this.teamPlanEndDateTo,
    this.extendToNextTeamPlan,
    this.isDeletionScheduled,
  });

  TeamSearchFilterParameters copyWith({
    String? keyword,
    TeamSearchRequestOrderBy? orderBy,
    bool? isOrderDesc,
    bool? isPlanPaid,
    bool? isTeamPlanActive,
    List<TeamType>? teamTypes,
    String? ownerEmail,
    DateTime? teamPlanStartDateFrom,
    DateTime? teamPlanStartDateTo,
    DateTime? teamPlanEndDateFrom,
    DateTime? teamPlanEndDateTo,
    bool? extendToNextTeamPlan,
    bool? isDeletionScheduled,
  }) {
    return TeamSearchFilterParameters(
      keyword: keyword ?? this.keyword,
      orderBy: orderBy ?? this.orderBy,
      isOrderDesc: isOrderDesc ?? this.isOrderDesc,
      isPlanPaid: isPlanPaid ?? this.isPlanPaid,
      isTeamPlanActive: isTeamPlanActive ?? this.isTeamPlanActive,
      teamTypes: teamTypes ?? this.teamTypes,
      ownerEmail: ownerEmail ?? this.ownerEmail,
      teamPlanStartDateFrom:
          teamPlanStartDateFrom ?? this.teamPlanStartDateFrom,
      teamPlanStartDateTo: teamPlanStartDateTo ?? this.teamPlanStartDateTo,
      teamPlanEndDateFrom: teamPlanEndDateFrom ?? this.teamPlanEndDateFrom,
      teamPlanEndDateTo: teamPlanEndDateTo ?? this.teamPlanEndDateTo,
      extendToNextTeamPlan: extendToNextTeamPlan ?? this.extendToNextTeamPlan,
      isDeletionScheduled: isDeletionScheduled ?? this.isDeletionScheduled,
    );
  }
}

@riverpod
class TeamSearchFilterParametersNotifier
    extends _$TeamSearchFilterParametersNotifier {
  @override
  TeamSearchFilterParameters build() {
    return const TeamSearchFilterParameters();
  }

  void updateKeyword(String? newKeyword) {
    state = TeamSearchFilterParameters(
      keyword: newKeyword,
      orderBy: state.orderBy,
      isOrderDesc: state.isOrderDesc,
      isPlanPaid: state.isPlanPaid,
      isTeamPlanActive: state.isTeamPlanActive,
      teamTypes: state.teamTypes,
      ownerEmail: state.ownerEmail,
      teamPlanStartDateFrom: state.teamPlanStartDateFrom,
      teamPlanStartDateTo: state.teamPlanStartDateTo,
      teamPlanEndDateFrom: state.teamPlanEndDateFrom,
      teamPlanEndDateTo: state.teamPlanEndDateTo,
      extendToNextTeamPlan: state.extendToNextTeamPlan,
      isDeletionScheduled: state.isDeletionScheduled,
    );
  }

  void updateOrderBy(TeamSearchRequestOrderBy newOrderBy) {
    state = state.copyWith(orderBy: newOrderBy);
  }

  void updateFilters({
    bool? isPlanPaid,
    bool? isTeamPlanActive,
    List<TeamType>? teamTypes,
    String? ownerEmail,
    DateTime? teamPlanStartDateFrom,
    DateTime? teamPlanStartDateTo,
    DateTime? teamPlanEndDateFrom,
    DateTime? teamPlanEndDateTo,
    bool? extendToNextTeamPlan,
    bool? isDeletionScheduled,
  }) {
    state = state.copyWith(
      isPlanPaid: isPlanPaid,
      isTeamPlanActive: isTeamPlanActive,
      teamTypes: teamTypes,
      ownerEmail: ownerEmail,
      teamPlanStartDateFrom: teamPlanStartDateFrom,
      teamPlanStartDateTo: teamPlanStartDateTo,
      teamPlanEndDateFrom: teamPlanEndDateFrom,
      teamPlanEndDateTo: teamPlanEndDateTo,
      extendToNextTeamPlan: extendToNextTeamPlan,
      isDeletionScheduled: isDeletionScheduled,
    );
  }

  void clearFilters() {
    state = const TeamSearchFilterParameters();
  }
}

